var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마?","JPN":"お母さん？","ENG":"Mom?","TWN":"媽媽？"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내가…… 엄마를 죽였어……?","JPN":"私が……お母さんを殺した……？","ENG":"I... killed my mom...?","TWN":"我……殺了媽媽……？"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"거짓말…… 거짓말……!","JPN":"嘘……ウソ……！","ENG":"No... That's a lie...!","TWN":"騙人……騙人……！"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"……거짓이 아니다. 레아 슈나이더.","JPN":"……噓ではない。レア・シュナイダー。","ENG":"...It is the truth, Leah Schneider.","TWN":"……沒有騙人，蕾亞·修奈德。"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가 열차에서 내리더라도 막을 수 없는 현실이다.","JPN":"そなたが列車から降りるとしても、阻止できない現実だ。","ENG":"That fact will not change even if you get off this train.","TWN":"即使你離開列車，也無法改變這個事實。"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니야…….","JPN":"いや……","ENG":"No...","TWN":"不……"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니야아아아아아!!","JPN":"いやああああああ！！","ENG":"IT CAN'T BE!!","TWN":"不！！！"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이런 걸 바란 적 없었어. 엄마가 미운 적도 있었지만…","JPN":"こんなことは望んでない。お母さんが憎いって思った時もあったけど……","ENG":"I never wanted this. I was angry at her from time to time...","TWN":"這不是我想要的。我雖然有時候會討厭媽媽…"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"감당하기 힘들다고 생각한 적도 많았지만…","JPN":"手に負えないって思った時も多かったけど……","ENG":"And countless times, I thought about how it was too much for me to handle...","TWN":"也經常感到自己無法再承受她……"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이렇게 되는 건, 이런 식으로는 바라지 않았단 말이야…….","JPN":"こうなるのは、こんな風には望んでなかった……","ENG":"But not like this. I never wanted it to be like this...","TWN":"但我從來沒有想過，會是這樣的結局……"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…………아.","JPN":"…………あ。","ENG":"...Ah.","TWN":"……啊。"},"stage":{"bg":"HARMONY2_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"죽여 버렸네요.","JPN":"殺してしまいましたね。","ENG":"I killed her.","TWN":"死掉了。"},"stage":{"bg":"HARMONY2_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……정말로.","JPN":"……本当に。","ENG":"...I really.","TWN":"真的……。"},"stage":{"bg":"HARMONY2_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"정말로, 죽여 버렸어요.","JPN":"本当に、殺してしまいました。","ENG":"I really... killed her.","TWN":"真的，死掉了。"},"stage":{"bg":"HARMONY2_04","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……아주머니?","JPN":"……おばさん？","ENG":"...Madam Schneider?","TWN":"伯母……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니!! 정신 차려요, 네?! 장난치지 말고 어서요!","JPN":"おばさん！！　しっかりしてください、ね！？　冗談はやめて、早く！","ENG":"Madam Schneider!! Wake up! This isn't the place nor time for games!","TWN":"伯母！！你快醒醒？！你別嚇我！快醒醒！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"브레히트 중사……?","JPN":"ブレヒト軍曹……？","ENG":"Sergeant Brecht...?","TWN":"布萊希特中士……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"큭!","JPN":"くっ！","ENG":"Khh!","TWN":"唔！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"커흑!!","JPN":"がはっ！！","ENG":"Kuh!!","TWN":"咳咳！！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……아. 설마, 함선 밖으로 튕겨져 나간 건가요.","JPN":"……あ。もしかして、艦船の外へと弾き飛ばされたのでしょうか。","ENG":"...Ah. Was she just thrown off the ship?","TWN":"……啊，是被彈飛出艦船外嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"곤란하군요. 새로운 단원으로 점찍었건만.","JPN":"困りましたね。新しい団員として目をつけていたのに。","ENG":"How unfortunate. I was hoping to recruit her as our new member.","TWN":"本來想選她為新的團員的，這樣可不行。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저런 저급한 인재에게 기대한 까닭은, 역시 인간으로서의 흔적일까요.","JPN":"あのような低レベルの人材に期待したのは、やはり人間として暮らしていたからなのでしょうか。","ENG":"Perhaps my desire for such low-quality talent is due to the leftover traces of my humanity.","TWN":"竟然會對那般低劣的人才抱有期待，是因為我作為人類的痕跡沒有被抹除嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"곤란해요…. 정말로….","JPN":"困りました……本当に……","ENG":"What an annoyance... this really is...","TWN":"這可不行……真是的……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇다면 분명히 지워졌어야 할 텐데….","JPN":"だったら、消えて然るべきなのですが……","ENG":"It should have definitely been erased…","TWN":"為什麼沒有被抹除乾淨……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"대체 뭐죠, 이 감각은? 어째서 이렇게나, 무절제한 박자로…….","JPN":"いったい何なのでしょうか、この感覚。どうしてこんなにも、節度のない拍子が……","ENG":"This feeling, what is it? How can it be this... unruly tempo...?","TWN":"這到底是什麼感覺？為什麼節拍會如此無節制地……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"……역시. 생각했던 대로네.","JPN":"……やっぱり。予想どおりだわ。","ENG":"...Of course. Just as I thought.","TWN":"……果然如我所料。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"셰나는 부정했지만, 지휘자님도 더 이상 예전 같지는 않으시단 말이야.","JPN":"シェナは否定していたけど、マエストロももう昔とは違うのよ。","ENG":"Shena denied it, but the Chief Conductor is not as she used to be.","TWN":"世娜雖然曾否認，但指揮家確實與從前不同。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"악단도 시대에 따라 변해야지.","JPN":"楽団も時代の流れに従って変わらないと。","ENG":"The Orchestra must also change in accordance with the times.","TWN":"樂團也要隨著時代而變化。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"지금보다 더 영리하게 이끌어 나갈 수 있는 지휘자를 통해서. 후훗.","JPN":"今よりもっと賢く導いていける指揮者と一緒にね。ふふっ。","ENG":"With a cleverer conductor than her. Fuu fuu.","TWN":"它需要一個更加出色的指揮家來領導。呵呵。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님. 지휘자님은 영원히 꿈 속에 남아 계시는 편이 나으셨어요.","JPN":"マエストロ。マエストロは永遠に夢の中にいらっしゃった方が良かったんです。","ENG":"Chief Conductor. You would've been better off staying in that dream forever.","TWN":"指揮家，你本應該永遠待在你的夢境裡。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그랬다면 제가 제일 아끼는 애완동물로 평생 동안 돌봐드렸을 텐데….","JPN":"そうしたら、私が一番お気に入りのペットとして一生お世話してあげられたのに……","ENG":"If you did, then I would have spent my entire lifetime taking care of you as my favorite pet...","TWN":"如果這樣，我就會把你當作我最喜歡的寵物愛惜……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"저는 셰나처럼 어리석게 복종만 하다가 죽을 생각은 없거든요.","JPN":"私はシェナみたいに、盲目的に服従した挙句に死ぬ気なんてさらさらないんです。","ENG":"You see, I don't want to die being the obedient fool that Shena was.","TWN":"我可不會像世娜一樣被你利用完就扔到一邊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"지금이라면…. 지휘자님의 핵을 가져갈 수…!","JPN":"今なら……マエストロの核を奪え……！","ENG":"But now... I can take your core–!","TWN":"而現在…我能奪走指揮家的核心…！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"──읏, 아.","JPN":"──ぐっ、あ。","ENG":"–Ngh, ah.","TWN":"──呃，啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"꺄아아아아아아악!!","JPN":"きゃあああああああっ！！","ENG":"Kyaaaaaah!!","TWN":"啊啊啊啊啊啊啊！！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"눈, 내 눈이……! 내 예쁜 눈이……!!","JPN":"目、私の目が……！　私の綺麗な目が……！！","ENG":"M-my eyes...! My beautiful eyes...!!","TWN":"我的眼睛……！我美麗的眼睛……！！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……그래요. 카르멘.","JPN":"……そうですね。カルメン。","ENG":"...I see, Carmen.","TWN":"……是嗎，卡門？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"잠시 애완동물로 지내 줬다고 크게 자만한 모양이군요.","JPN":"しばらくペットとして暮らしてあげたからといって、だいぶ自惚れてしまったようですね。","ENG":"It seems that you have become overconfident because I was temporarily your pet.","TWN":"把我當寵物對待的日子裡，你竟然變得如此傲慢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신의 계획은 모략도 무엇도 아닌 약은 꾀에 불과한 것을.","JPN":"あなたの計画は謀略でも何でもなく、ただの子ども騙しに過ぎません。","ENG":"However, your so-called plans are nothing more than schemes.","TWN":"你的計畫只是一個小把戲，甚至都算不上謀略。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"아, 아흑……! 아아……!","JPN":"あ、あうっ……！　ああ……！","ENG":"A-agh...! Aah...!","TWN":"啊啊啊……！啊啊……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어떻게…… 분명히, 힘이 약해졌을 텐데……!","JPN":"どうして……確かに、力が弱まっていたはずなのに……！","ENG":"How...? But surely, you must have been weakened...!","TWN":"怎麼會……你的力量已經被削弱了才對……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"인간들에게 빌붙어 저를 노린다는 발상은 나쁘지 않았습니다.","JPN":"人間にへつらい、私を狙うという発想は悪くありませんでした。","ENG":"The idea of siding with the humans to bring me down was not such a terrible idea.","TWN":"透過與人類勾結，試圖奪走我的性命，這個主意倒是很不錯。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"혼란스러운 틈을 타서 제 핵을 빼앗을 속셈이었죠?","JPN":"混乱に紛れ、私の核を奪うつもりだったのでしょう？","ENG":"You were attempting to steal my core amidst this chaos, were you not?","TWN":"你原本是想趁著混亂，搶走我的核心吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"하지만 이따금, 몸소 나서서 배신자를 걸러내야 할 때가 있습니다.","JPN":"ですが、時によっては自ら直接裏切り者を間引く必要があります。","ENG":"But there are times when I have to weed out the traitors myself.","TWN":"不過呢，我有時候也不得不親自出面找出叛徒。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"직접 움직이지 않고 칩거하면 경솔하게 움직이는 자들이 나타나기 마련이더군요.","JPN":"直接動かずに引きこもっていると、軽率に行動する者たちが現れるものです。","ENG":"The more I stay in, the more I find my underlings to move rashly.","TWN":"如果我總是安靜地蟄伏，總會出現一些輕舉妄動的人。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그렇다면…. 처음부터 이러려고…….","JPN":"だったら……最初からこうするために……","ENG":"Then... this was your plan all along...","TWN":"這麼說……你從一開始就打算……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"아아아아아아악! 다리……! 내 다리가……!","JPN":"ああああああああ！　足……！　私の足が……！","ENG":"AAAAGH! My leg...! MY LEG...!","TWN":"啊啊啊啊！腿……！我的腿……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"자아, 저기 출구가 있군요. 카르멘. 살고 싶다면 열심히 기어가 보시길.","JPN":"さあ、あそこに出口がありますね。カルメン。生きたければ頑張って這ってみてください。","ENG":"Now, the exit is over there, Carmen. Crawl out of here if you wish to live.","TWN":"看，那邊就是出口。卡門，如果想活命，就努力爬出去吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흑, 흐윽……! 끄흑……!","JPN":"うっ、ううっ……！　ぐふっ……！","ENG":"H-hrgh...! Ngggh...!","TWN":"嗚嗚……！嗚……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"살려 줘……. 살려 주세요……. 지휘자님, 제, 제발…….","JPN":"助けて……助けてください……マエストロ、ど、どうか……","ENG":"Have mercy... Chief Conductor, please... M-mercy...","TWN":"救命……請你饒了我吧……指揮家，求求你……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇다면 당신의 가치를 피력해 보세요.","JPN":"なら、自分の価値を示すことです。","ENG":"Then appeal your value to me.","TWN":"那就說說你還有什麼價值吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저 볼품없는 늙은이를 보세요. 가축을 기르는 재주마저 별볼일 없지 않았나요?","JPN":"あのみすぼらしい老婆をご覧なさい。家畜を飼う能力も大したことなかったではありませんか。","ENG":"Look at that old woman. Even your talent for raising pets is worthless, don't you think?","TWN":"你不是很擅長照料寵物嗎？可是你看看那老太婆，照料得也不算好吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"아니에요…! 아니에요, 지휘자님!","JPN":"違います……！　違います、マエストロ！","ENG":"No...! That is not true, Chief Conductor!","TWN":"不是的……！不是這樣的，指揮家！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"인간들은 제멋대로니까, 다루기 쉽게 연주로 머리를 조금씩 건드렸을 뿐이에요.","JPN":"人間は自分勝手ですから、扱いやすくするために演奏で頭を少しずついじっただけなんです。","ENG":"Humans do as they please. All I did was play a song to make them easier to control.","TWN":"人類總是不愛聽話，所以為了方便照顧，我就用演奏稍微影響她的腦子而已。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님도 아시잖아요? 배가 고프다느니, 바람을 쐬고 싶다느니, 상전처럼 칭얼거리기나 하니까……!","JPN":"マエストロもご存じでしょう？　腹が減っただの、風に当たりたいだの、主人みたいにぶつぶつ文句を言うから……！","ENG":"You know that already, Chief Conductor! They always complain about being hungry and needing fresh air, as if we were servants–!","TWN":"指揮家不是也知道嗎？她總是一直吵，一下說什麼肚子餓，一下說什麼想出去散步……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"아윽, 아──","JPN":"はうっ、あ──","ENG":"Agh, ah–","TWN":"呃，呃呃──"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"죽음이 눈앞에 닥쳤는데 부산스럽지 못한 손가락은 필요없겠죠.","JPN":"目の前に死が迫っているのに、動きもしない指なんていらないでしょう。","ENG":"You will not need these lazy fingers when death is staring directly at you.","TWN":"既然已經死到臨頭，這些礙眼的手指頭就不必留下了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"캬아아아아아악! 아아아악!","JPN":"きゃああああああっ！　ああああ！","ENG":"Kaaaaagh! AAAGH!","TWN":"啊啊啊啊啊！啊啊啊！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L47_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흠. 흐흠. 흠.","JPN":"ふーん、ふふーん、ふーん。","ENG":"*Humming*","TWN":"嗯，呵嗯，嗯。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"좋아요. 당신의 가치를 찾았어요, 카르멘.","JPN":"良いでしょう。あなたの価値を見つけました、カルメン。","ENG":"Very well. I found you your worth, Carmen.","TWN":"很好，我找到你的價值了，卡門。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"더 힘차게 소리를 높여 보세요. 인간의 몸을 빌려서인지 비명이 각별하군요.","JPN":"もっと力強く声を上げてみてください。人間の身体を借りているからか、悲鳴が格別ですね。","ENG":"Scream louder for me. Maybe it is because you are borrowing a mortal's vessel, but your screams are exquisite.","TWN":"叫得更大聲一些吧。是因為借用人類的身體嗎？你的慘叫聽起來格外動聽。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"케흑……! 흑……! 내가, 어떻게 가꾼 몸인데……!","JPN":"ゲホッ……！　うっ……！　私が、丁寧に作り上げた身体なのに……！","ENG":"Kuh...! Hrgh...! D-do you know how much effort I put into this vessel...?!","TWN":"咳……！咳……！我、我好不容易照料的身體……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"죽여, 차라리 죽여 줘……!","JPN":"殺して、いっそ殺して……！","ENG":"Just kill me. End me now...!","TWN":"快…快殺了我吧……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"모쪼록 이해해 주시길.","JPN":"ごめんなさい。","ENG":"Please understand.","TWN":"希望你能理解。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예우를 갖춰 당신을 처분해서는…. 제 심경이 가라앉지 않을 듯하군요.","JPN":"あなたの処分に礼を尽くせば……私の心が落ち着かないと思います。","ENG":"My frustration will not be satiated... if I dispose of you with courtesy.","TWN":"如果我禮貌地處決你…就無法平復我的內心。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"내, 내 핵으로… 뭐 하려는…. 거야……?","JPN":"わ、私の核で……何をしようと……してるの……？","ENG":"W-what are you... doing with... my core...?","TWN":"你…你想用我的核心……做什麼……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"감사히 여기세요, 카르멘. 당신의 비명이 마음에 들었습니다.","JPN":"ありがたく思いなさい、カルメン。あなたの悲鳴が気に入りました。","ENG":"Be grateful, Carmen. I enjoyed hearing your cries.","TWN":"感謝我吧，卡門。你的慘叫非常令人滿意。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"가수로 삼아 모두의 주목을 받게 만들어 드리지요.","JPN":"歌手にし、みんなに注目されるようにしてあげましょう。","ENG":"Thus, I shall turn you into a singer so you can get everyone's attention.","TWN":"我會把它用於歌手，讓你受到大家的矚目。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"아, 안 돼…… 그런 흉측한 꼴은 싫어……!","JPN":"だ、ダメ……あんなブサイクな姿はイヤ……！","ENG":"N-no...! I don't want to be hideous...!","TWN":"不…不要……我不要變成那醜陋的樣子……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"하지 마, 제발……!","JPN":"やめて、お願い……！","ENG":"Please... don't do this...!","TWN":"求求你，快住手……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그러니 부디….","JPN":"ですので、どうか……","ENG":"So please...","TWN":"所以，請你……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아름답게 울어 주시길.","JPN":"美しく鳴いてください。","ENG":"Sing for me.","TWN":"美麗地哭泣吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};